import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as t,a as s}from"./app-9b6e0af7.js";const l={},n=s(`<h1 id="tervezzunk-es-epitsunk-fel-egy-adatbazist" tabindex="-1"><a class="header-anchor" href="#tervezzunk-es-epitsunk-fel-egy-adatbazist" aria-hidden="true">#</a> Tervezzünk és építsünk fel egy adatbázist</h1><div class="hint-container note"><p class="hint-container-title">Ennek a témakörnek az a célja, hogy</p><ul><li>megtervezzünk egy adatbázist</li><li>létrehozzunk egy minta adatbázist</li><li>adatbázisokat hozzunk létre</li></ul></div><p>Az adatbázisok létrehozásának első lépése a tervezés. Az adatbázist jóval azelőtt megtervezed, hogy akár csak egy ujjal is hozzányúlnál a billentyűzethez és létrehoznád az adatbázist - jó esetben 🙄. A tervezés a legfontosabb lépés. Nagyon fájdalmas élmény, ha akkor fedezed fel, hogy az adatbázisban nincs meg minden adat, vagy az adatok között hiányzik valamilyen kapcsolat, melyre szükséged lenne, mikor már felépítetted az adatbázist és elkezdted használni.</p><p>Ha kész vagy az adatbázisod tervezésével akkor készen állsz arra, hogy fel is építsd azt. A terv alapján hozhatod majd létre az adatbázisodat és annak tábláit, melyet magad alakítottál ki. Ha már felépítetted lesz egy használható, üres adatbázisod mely csak arra vár, hogy feltöltsd adatokkal.</p><h3 id="tervezzunk-adatbazist" tabindex="-1"><a class="header-anchor" href="#tervezzunk-adatbazist" aria-hidden="true">#</a> Tervezzünk adatbázist</h3><p>Adatbázisok tervezése során azonosítanod kell, hogy milyen adatokra lesz szükséged és ezeket az adatokat az adatbázisszoftver követelményeinek megfelelően kell rendezned. Ahogy megalkotod az adatbázis tervedet minden táblához meg kell adnod egy elsődleges kulcsot is, hogy tudjanak kapcsolódni egymáshoz. Azt is meg kell fontolnod továbbá, hogy a táblákban milyen típusú adatokat fogsz tárolni.</p><h3 id="adatok-kivalasztas" tabindex="-1"><a class="header-anchor" href="#adatok-kivalasztas" aria-hidden="true">#</a> Adatok kiválasztás</h3><p>Egy adatbázis megtervezése során először meg kell határoznod, hogy milyen információk kerüljenek bele. Az adatbázisnak minden szükséges adatot tartalmaznia kell ahhoz, hogy elérhesse a célját.</p><p>Nézzük a következő példákat:</p><ul><li>Egy online katalógushoz egy olyan adatbázis kell, mely termékek információit tartalmazza.</li><li>Egy online rendelőalkalmazáshoz olyan adatbázisra lesz szükséged, mely tárolni tudja a vásárlók és rendeléseik információit.</li><li>Egy utazási weboldalhoz olyan adatbázis szükséges, mely a célpontok, a foglalások, a díjak, az időbeosztások adatait tartalmazzák.</li></ul><p>Az alkalmazásunk sok esetben tartalmazhat egy olyan feladatot is mely során a felhasználótól gyűjt be információkat. Az olyan vásárlóknak például, akik termékeket vásárolnak a weboldalról, meg kell adniuk a címüket, telefonszámukat, bankkártya információikat és más egyéb adataikat is ahhoz, hogy elküldhessék a rendelésüket. Ezeket az információkat pedig legalább addig tárolnod kell, amíg nem teljesíted a rendelést. A weboldalak gyakran megtartják a vásárlói információkat, hogy elősegítsék később rendelések elküldését mert így a vásárlónak nem kell majd ismét beírnia minden adatát, amikor leadja a következő rendelését.</p><p>Egy vásárlói adatbázis például a következő adatokat gyűjtheti be:</p><ul><li>Név</li><li>Cím</li><li>Telefonszám</li><li>Email cím</li></ul><div class="hint-container note"><p class="hint-container-title">Szánd rá az időt, hogy összeállíts egy átfogó listát azokról az információkról melyeket tárolnod kell az adatbázisodban! Bár az adatbázisod adatait azután is módosíthatod vagy bővítheted, hogy kialakítottad azt sokkal könnyebb, ha az elejétől fogva felveszed az információkat és így valószínűleg az azzal járó pluszmunkát is elkerülheted, hogy később módosítsd az adatbázisodat. Ha később veszel fel információkat az adatbázisodba - amikor már használod azt - akkor azok az adatok amik szerepelnek benne hiányosak lesznek. Például, ha úgy módosítasz egy űrlapot, hogy most már szükséged van a felhasználók életkorára is akkor akik már kitöltötték az űrlapot azoknak a koráról nem fogsz tudni.</p></div><h3 id="adatok-szervezese" tabindex="-1"><a class="header-anchor" href="#adatok-szervezese" aria-hidden="true">#</a> Adatok szervezése</h3><p>Az MySQL egy relációs adatbáziskezelő rendszer (RDBMS - Relational Database Management System), ami azt jelenti, hogy az adatokat táblákba szervezi. Az RDBMS táblák ugyanúgy vannak szervezve, mint bármilyen más táblázat, melyekkel találkozhatsz - sorokból és oszlopokból állnak, ahogy azt a következő táblázatban is láthatod.</p><table><thead><tr><th></th><th>1. oszlop</th><th>2. oszlop</th><th>3. oszlop</th><th>4. oszlop</th></tr></thead><tbody><tr><td>1. sor</td><td></td><td></td><td></td><td></td></tr><tr><td>2. sor</td><td></td><td></td><td></td><td></td></tr><tr><td>3. sor</td><td></td><td></td><td></td><td></td></tr><tr><td>4. sor</td><td></td><td></td><td></td><td></td></tr></tbody></table><p>Azokat az egyedi cellákat, melyek egy adott sor és egy adott oszlop metszetében vannak, mezőknek nevezzük.</p><p>Minden tábla egy olyan objektumra koncentrál, amelyről szeretnél információkat tárolni. Nézzünk néhány példát ilyen objektumokra:</p><ul><li>Vásárlók</li><li>Termékek</li><li>Könyvek</li><li>Számítógépek</li><li>Alakzatok</li><li>Városok</li></ul><div class="hint-container tip"><p class="hint-container-title">Minden objektumhoz létre kell hoznod egy táblát. A tábla nevének egy beszédes szóval vagy kifejezéssel kell meghatároznia, hogy milyen objektumokat tartalmaz, a következő irányelveknek megfelelően.</p><ul><li>A nevének egy karaktersztringnek kell lennie, mely betűket, számokat, aláhúzásokat tartalmazhat, de szóközöket nem.</li><li>A táblákat egyes számban szokás elnevezni. Így a vásárlóid táblája lehet <code>Vasarlo</code>, a vásárlóid megrendeléseit tartalmazó tábla pedig lehet <code>VasarloiRendeles</code>.</li><li>UNIX-on lényeges a kis és nagybetűk közötti különbség, Windows-on viszont nem. Ennek tudatában a legjobb, ha figyelsz a kis és nagybetűk különbségeire abban az esetben, ha esetleg a kiszolgáló környezetet kell cserélgetned.</li></ul></div><p>Adatbázisos nyelven szólva az objektumok <strong>entitások</strong>, az entitásoknak pedig <strong>attribútumaik</strong> vannak. A táblákban minden sor egy entitást képvisel és az oszlopok tartalmazzák az egyes entitások attribútumait. A vásárlók táblájában például minden sor egy adott vásárló adatait tartalmazza. Az oszlopokban tárolt attribútumok között olyasmik fordulhatnak elő mint a vezetéknév, keresztnév telefonszám vagy az életkor.</p><p>A következő lépésekkel eldöntheted, hogyan szervezed az adataidat táblákba:</p><ol><li><strong>Nevezd el az adatbázisodat!</strong></li></ol><p>Adj meg egy nevet az adatbázisnak, melyet használni szeretnél az alkalmazásodhoz.</p><ol start="2"><li><strong>Azonosítsd az objektumokat!</strong></li></ol><p>Nézd végig azon információk listáját, melyeket tárolni szeretnél az adatbázisodban. Elemezd a listádat és határozd meg az objektumokat.</p><ol start="3"><li>Minden objektumhoz definiálj és nevezz el egy táblát!</li></ol><p>Például egy <code>Bolt</code> nevű adatbázisban egy <code>Vasarlo</code> és egy <code>Termekek</code> táblára lesz szükséged.</p><ol start="4"><li><strong>Azonosítsd az egyes objektumok attribútumait!</strong></li></ol><p>Elemezd az információid listáját és keresd meg, hogy az egyes objektumoknak milyen attribútumokat kell tárolniuk. A tárolni kívánt információkat bontsd le a lehető legkisebb ésszerű csoportokba. Ha például egy személy nevét tárolod egy táblában akkor a nevet vezetéknévre és keresztnévre bonthatod. Ha így teszel, akkor tudsz majd keresztnév szerint is rendezni, amely kissé nehéz lenne, ha a vezeték- és keresztnevet együtt tárolnád. A nevet akár még vezetéknév, keresztnév és második név részekre is bonthatod, habár nem sok helyen kell külön kezelned az emberek második keresztnevét.</p><ol start="5"><li><strong>Definiálj egy oszlopot és add meg az oszlopnevet minden egyes attribútumhoz melyet meghatároztál!</strong></li></ol><p>Minden egyes oszlopnak olyan nevet adj, mely világosan bemutatja hogy milyen információt tárol az adott oszlop. Az oszlop neve egyszavas legyen, szóközök nélkül. Az oszlopod neve lehet például <code>vezeteknev</code> és <code>keresztnev</code> vagy <code>vezetek_nev</code> és <code>kereszt_nev</code>.</p><p>Az SQL-ben van néhány foglalt szó melyeket használnak és így mi nem használhatjuk azokat oszlopnévként. Ezek a szavak az SQL utasításokban vannak jelenleg is használatban vagy pedig későbbi használatra vannak fenntartva. Nem használhatod például az <code>ADD</code>, <code>ALL</code>, <code>AND</code>, <code>CREATE</code>, <code>DROP</code>, <code>GROUP</code>, <code>ORDER</code>, <code>RETURN</code>, <code>SELECT</code>, <code>SET</code>, <code>TABLE</code>, <code>USE</code>, <code>WHERE</code> szavakat és még sok-sok más szót oszlopnévként.</p><ol start="6"><li><strong>Határozd meg az elsődleges kulcsot!</strong></li></ol><p>Egy táblában minden sornak kell, hogy legyen egy egyedi azonosítója. Egy táblán belül nem lehet két olyan sor, melyek teljesen egyformák. Amikor megtervezed a tábládat, el kell döntened, hogy melyik oszlopban legyen az egyedi azonosító, az úgynevezett <strong>elsődleges kulcs</strong>.</p><p>Az elsődleges kulcs egynél több érték kombinációja is lehet. Sok esetben az objektumaid attribútumai nem adnak egyedi azonosítót. Ha például van egy vásárló táblád akkor abban lehet, hogy nincs egyedi azonosító mert két vásárlót hívhatnak ugyanúgy. Ha nincs egyedi azonosító oszlopod akkor létre kell hoznod egyet kifejezetten azért, hogy elsődleges kulcs legyen. Erre a célra gyakran egy sorszámokat tartalmazó oszlopot használnak. A következő táblázatban például az elsődleges kulcs a <code>vasarlo_azon</code> mező, mivel minden vásárlónak egyedi azonosítószáma van.</p><table><thead><tr><th>vasarlo_azon</th><th>vezeteknev</th><th>keresztnev</th><th>telefon</th></tr></thead><tbody><tr><td>27863</td><td>Kovács</td><td>János</td><td>555-555</td></tr><tr><td>44532</td><td>Lugosi</td><td>Béla</td><td>555-553</td></tr><tr><td>22312</td><td>Csongrádi</td><td>Judit</td><td>555-554</td></tr><tr><td>11296</td><td>Szabó</td><td>Júlia</td><td>555-552</td></tr></tbody></table><ol start="7"><li><strong>Határozd meg az alapértelmezett értékeket</strong></li></ol><p>Meghatározhatsz olyan alapértelmezett értékeket, melyeket az SQL hozzárendel az egyes mezökhöz, ha az adott mezőhöz nem adsz meg adatot. Nem kötelező alapértelmezett értéket megadnod, de ez gyakran hasznos lehet.</p><h3 id="kapcsolatok-letrehozasa-tablak-kozott" tabindex="-1"><a class="header-anchor" href="#kapcsolatok-letrehozasa-tablak-kozott" aria-hidden="true">#</a> Kapcsolatok létrehozása táblák között</h3><p>Egy adatbázis egyes táblái kapcsolódhatnak egymáshoz. Legtöbbször egy tábla egy sora egy másik tábla több sorához kapcsolódik. Szükséged lesz egy oszlopra, mellyel összekapcsolhatod az egymáshoz kötődő sorokat a különböző táblákban. Sok esetben kell majd szúrnod egy oszlopot az egyik táblába, hogy olyan adatokat tárolj benne, melyek illeszkednek egy másik tábla elsődleges kulcs értékeire.</p><p>Elég elterjedtek például a vásárlók rendeléseit kezelő alkalmazások melyekhez két egymáshoz kapcsolódó táblára lesz szükséged. Az egyik tábla tárolhatja a vásárlók információit, például a nevüket, címüket és a telefonszámukat. Minden vásárlónak lehet nulla vagy akár rengeteg rendelése. A rendelések információit tárolhatnád a vásárlói adatokkal egy táblában is, de ebben minden egyes alkalommal amikor egy felhasználó lead egy megrendelést, létrejönne egy új sor és minden új sor tartalmazná a vásárló összes információját is. Ennél sokkal hatékonyabban tárolhatod a rendelések információit egy különálló táblában melyeknek lehet a neve mondjuk <code>VasarloiRendeles</code>. A <code>VasarloiRendeles</code> táblában megadhatsz egy olyan oszlopot mely a <code>Vasarlo</code> tábla elsődleges kulcsait tartalmazza és így a rendeléseket a <code>Vasarlo</code> tábla megfelelő sorához kapcsolhatod.</p><p>Minden vásárlónak van egy egyedi <code>vasarlo_azon</code> értéke. Az ehhez kapcsolódó <code>VasarloiRendeles</code> táblában láthatod, hogy megtalálod <code>vasarlo_azon</code> oszlopot mely a <code>Vasarlo</code> táblában is szerepel.<br> A rendeléseknek a <code>VasarloiRendeles</code> táblában szereplő információi ezen az oszlopon keresztül kapcsolódnak a vásárló nevéhez és telefonszámához a <code>Vasarlo</code> táblában.</p><table><thead><tr><th>rendeles_azon</th><th>vasarlo_azon</th><th>termeknev</th><th>ar</th></tr></thead><tbody><tr><td>87-222</td><td>27863</td><td>póló</td><td>20</td></tr><tr><td>87-223</td><td>44532</td><td>cipő</td><td>40</td></tr><tr><td>87-224</td><td>22312</td><td>kalap</td><td>35</td></tr><tr><td>87-225</td><td>11296</td><td>sál</td><td>15</td></tr></tbody></table><p>Ebben a példában a <code>Vasarlo</code> táblát és a <code>VasarloiRendeles</code> táblát összekötő oszlopok neve megegyezik. A nevük lehetne különböző is, ha az oszlopok ugyanazokat az adatokat tartalmazzák.</p><h3 id="adattipusok" tabindex="-1"><a class="header-anchor" href="#adattipusok" aria-hidden="true">#</a> Adattípusok</h3><p>Az SQL különböző formátumokban tárolja az adatokat attól függően, hogy milyen információtípusok érkezésére készíted fel. Az SQL-ben különböző adattípusokat különböző módokon használhatjuk. A fő adattípusok a karakter, a szám, a dátum és az időadatok. A következőkben ezekről és más adattípusokról olvashatsz majd pedig azt is megnézzük, hogy egyes oszlopokhoz milyen adattípust fogunk használni.</p><h4 id="karakter-adattipus" tabindex="-1"><a class="header-anchor" href="#karakter-adattipus" aria-hidden="true">#</a> Karakter adattípus</h4><p>Az adatok legelterjedtebb típusa a karakteres adatok ezeket csak sztringekként kezelheted. A legtöbb információ karakteres adatként van tárolva például a vásárlók neve, címe, telefonszáma. A karakteres adatokat mozgathatod és kiírathatod. Két karaktersztringet összeilleszthetsz, kivághatsz egy hosszabb sztringből egy részsztringet és egy sztringet behelyettesíthetsz egy másik helyére.</p><h4 id="numerikus-adattipus" tabindex="-1"><a class="header-anchor" href="#numerikus-adattipus" aria-hidden="true">#</a> Numerikus adattípus</h4><p>Az adatok másik gyakori típusa a numerikus adatok - azok az adatok melyeket számokként tárolhatsz. Tárolhatsz tizedes törteket és egész számokat. Amikor számként tárolsz el egy adatot akkor az adataidat felhasználhatod numerikus műveletekben, például összeadhatod, kivonhatod vagy négyzetre emelheted. Ha nem tervezed numerikus műveletekben használni az adataidat akkor viszont inkább karaktersztringként tárold őket, mert a programozó karaktersztringként fogja használni és így nem lesz szükség konverzióra.</p><h4 id="datum-es-ido-adattipus" tabindex="-1"><a class="header-anchor" href="#datum-es-ido-adattipus" aria-hidden="true">#</a> Dátum és idő adattípus</h4><p>A harmadik gyakori adattípus a dátum és idő adatok. A dátumként tárolt adatok számos különböző dátumformátumban megjelenítheted. Ezen adatok segítségével meghatározhatod az időt, amely eltelt két dátum vagy két időpont között.</p><h4 id="az-sql-adattipusok-nevei" tabindex="-1"><a class="header-anchor" href="#az-sql-adattipusok-nevei" aria-hidden="true">#</a> Az SQL adattípusok nevei</h4><p>Amikor egy adatbázist hozol létre meg kell adnod milyen típusú adatokra számíthat egyes oszlopban az SQL. Számos más adattípust is használhatsz azok mellett amelyeket a lenti táblában láthatsz. Jelen esetben a gyakran használt adattípusokat mutatom be neked!</p><table><thead><tr><th>Adattípus</th><th>Leírás</th></tr></thead><tbody><tr><td><code>CHAR</code></td><td>Rögzített hosszúságú karakter sztring.</td></tr><tr><td><code>VARCHAR</code></td><td>Változó hosszúságú karakter sztring 1 és 255 között.</td></tr><tr><td><code>INT</code></td><td>- 2 147 483 648 és 2 147 483 648 közötti egész szám.</td></tr><tr><td><code>DECIMAL</code></td><td>Tizedes tört.</td></tr><tr><td><code>DATE</code></td><td>Dátumérték, évvel, hónappal és nappal. <code>YYYY-MM-DD</code></td></tr><tr><td><code>DATETIME</code></td><td>Dátum és idő együtt tárolva. <code>YYYY-MM-DD HH:MM::SS</code></td></tr></tbody></table><h3 id="adatbazis-megtervezese" tabindex="-1"><a class="header-anchor" href="#adatbazis-megtervezese" aria-hidden="true">#</a> Adatbázis megtervezése</h3><p>Most megnézzük, hogyan tervezünk adatbázist amely a vásárlók információit tartalmazza. Írd le azon információk listáját melyeket tárolni szeretnél minden vásárló esetén az alábbiak szerint: <strong>Név, Cím, Telefonszám, Email.</strong></p><p>Emellett, az információkat arról is be kell gyűjtened, hogy a vásárlók milyen termékeket rendelnek meg. Minden egyes rendeléshez be kell gyűjtened a következő információkat: <strong>rendelés leadásának ideje, adott rendelésben szereplő egyes termékinformációi.</strong><br> Ebben a példában a termékek pólók. Így a következő információkra lesz szükséged minden egyes cikkhez: <strong>Termék azonosító, Méret, Ár, Szín.</strong></p><p>A <code>Vasarlo</code> adatbázist a következő lépésekben alakíthatod ki:</p><ol><li><strong>Nevezd el az adatbázisodat</strong></li></ol><p>A rendelések információit tároló adatbázis neve legyen <code>VasarloiRendelesInformaciok</code></p><ol start="2"><li><strong>Azonosítsd az objektumokat</strong></li></ol><p>Az információk listája a következő:</p><ul><li>Vásárló neve</li><li>Vásárló címe</li><li>Vásárló telefonszáma</li><li>Vásárló email címe</li><li>Rendelés leadásának ideje</li><li>Konkrét terméket azonosító szám</li><li>Méret</li><li>Szín</li><li>Ár</li></ul><p>Az első öt információelem a vásárlókhoz tartozik, szóval az egyik objektumod a <code>Vasarlo</code> lesz. A rendelés ideje a teljes rendeléshez tartozik szóval egy másik objektum a <code>VasarloiRendeles</code> lesz.<br> A fennmaradó négy adat a rendelésekhez tartozó egyes tételek sajátja, tehát az utolsó objektum a <code>RendelesiTetel</code> lesz.</p><ol start="3"><li><strong>Minden objektumhoz definiálj és nevezz el egy táblát</strong></li></ol><p>A <code>VasarloiRendelesInformaciok</code> adatbázisban a következő táblákra lesz szükséged:</p><ul><li><code>Vasarlo</code></li><li><code>VasarloiRendeles</code></li><li><code>RendelesiTetel</code></li></ul><ol start="4"><li><strong>Azonosítsd az egyes objektumok attribútumait</strong></li></ol><p>Tekintsd az információid listáját részletesebben is:</p><ul><li>Vásárló azonosítója: Attribútum - egyedi azonosító minden vásárlóhoz</li><li>Vásárló neve: Két attribútum - vezetéknév és keresztnév</li><li>Vásárló címe: Négy attribútum - megye, irányítószám, város, utca neve</li><li>Vásárló telefonszáma: egy attribútum</li><li>Vásárló email címe: egy attribútum</li><li>Rendelés száma: egy attribútum - egyedi azonosító minden rendeléshez</li><li>Rendelés leadásának ideje: egy attribútum</li><li>Konkrét termékazonosító szám: egy attribútum</li><li>Méret: egy attribútum</li><li>Szín: egy attribútum</li><li>Ár: egy attribútum</li></ul><ol start="5"><li><strong>Definiálj és nevezd el az oszlopokat</strong></li></ol><p>A <code>Vasarlo</code> tábla minden egyes vásárlóhoz egy sort tartalmaz. A <code>Vasarlo</code> tábla oszlopai a következők:</p><ul><li><code>vasarlo_azon</code></li><li><code>vezeteknev</code></li><li><code>keresztnev</code></li><li><code>utca</code></li><li><code>varos</code></li><li><code>megye</code></li><li><code>iranyitoszam</code></li><li><code>email</code></li><li><code>telefon</code></li></ul><p>A <code>VasarloiRendeles</code> tábla minden egyes rendeléshez tartalmaz egy sort melyek a következő oszlopokat foglalják magukba:</p><ul><li><code>vasarlo_azon</code> - <em>Ez az oszlop kapcsolja össze ezt a táblát a <code>Vasarlo</code> táblával. Ez az érték egyedi a <code>Vasarlo</code> táblában, ebben a táblában viszont nem az!</em></li><li><code>rendeles_azon</code></li><li><code>rendelesidatum</code></li></ul><p>A <code>RendelesiTetel</code> tábla minden egyes rendelés tételhez, tartalmaz egy sort melyek a következő oszlopokat tartalmazzák:</p><ul><li><code>katalogus_azon</code></li><li><code>rendeles_azon</code> - <em>Ez az oszlop kapcsolja össze ezt a táblát a <code>VasarloiRendeles</code> táblával. Ez az érték egyedi a <code>VasarloiRendeles</code> táblában, ebben a táblában viszont nem az!</em></li><li><code>meret</code></li><li><code>szin</code></li><li><code>ar</code></li></ul><ol start="6"><li><strong>Határozd meg az elsődleges kulcsot</strong></li></ol><p>A <code>Vasarlo</code> tábla elsődleges kulcsa a <code>vasarlo_azon</code> oszlop. Így a <code>vasarlo_azon</code> értéke egyedi kell, hogy legyen. A <code>VasarloiRendeles</code> tábla elsődleges kulcsa a <code>rendeles_azon</code> oszlop.<br> A <code>RendelesiTetel</code> tábla elsődleges kulcsa a <code>katalogus_azon</code> és a <code>rendeles_azon</code> oszlopok együttese lesz.</p><ol start="7"><li><strong>Határozd meg az alapértelmezett értékeket</strong></li></ol><p>Ezekben a táblákban nem adunk meg semmilyen alapértelmezett értéket.</p><ol start="8"><li><strong>Határozd meg, hogy mely oszlopok kitöltése kötelező</strong></li></ol><p>A következő oszlopok soha nem lehetnek üresek:</p><ul><li><code>vasarlo_azon</code></li><li><code>rendeles_azon</code></li><li><code>katalogus_azon</code></li></ul><p>Ez a három oszlop adja az elsődleges kulcsokat. Soha ne engedd, hogy ezen értékek nélkül kerüljön be egy sor a táblákba.</p><ol start="9"><li><strong>Döntsd el, hogy az egyes attribútumok tárolásához milyen adattípusokat fogsz használni</strong></li></ol><ul><li>Numerikus: A <code>vasarlo_azon</code> és a <code>renedles_azon</code> numerikus típusú.</li><li>Dátum: A <code>rendelesidatum</code> dátum típusú</li><li>Karakteres: Minden más mező karakteres adattípusú.</li></ul><h3 id="adatbazis-terv-leirasa" tabindex="-1"><a class="header-anchor" href="#adatbazis-terv-leirasa" aria-hidden="true">#</a> Adatbázis terv leírása</h3><p>Valószínűleg rengeteg időt töltöttél azzal, hogy meghoztad a tervezési döntéseket az adatbázisodhoz. A döntéseid most már véglegesek.<br> Valószínűleg nem hiszed, hogy elfelejtenéd őket. Tegyük fel azonban, hogy valami halaszthatatlan jön közbe ezzel a projekttel nem tudsz foglalkozni két hónapig.<br> Újra elemezheted az adataidat és minden tervezési döntést is újra meg kell hoznod, ha az eredetileg meghozott döntéseidet nem írtad le.</p><p>Írd le a táblák elrendezését az oszlopneveket és minden más tervezési döntésedet is. A dokumentumodban minden táblát táblázat formájában írj le, melyben minden oszlophoz van egy sorod és<br> minden tervezési döntéshez van egy oszlop. Az oszlopaid lehetnek például a következők: <code>oszlop neve</code>, <code>adattípus</code> és <code>leírás</code>.</p><h3 id="adatbazis-letrehozasa" tabindex="-1"><a class="header-anchor" href="#adatbazis-letrehozasa" aria-hidden="true">#</a> Adatbázis létrehozása</h3><p>Ha egy új adatbázist akarsz létrehozni az első lépésben létre kell hoznod egy üres adatbázist és el kell nevezned. Az adatbázisod neve legfeljebb 64 karakter hosszú lehet. Néhány kivételtől eltekintve használhatsz betűket, számokat és írásjeleket. Általánosan elmondható, hogy olyan karaktereket nem használhatsz melyek az operációs rendszered könyvtárneveiben sem megengedettek.</p><p>A következő SQL utasítást használod egy új adatbázis létrehozásához:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">DATABASE</span> adatbazisnev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ebben az utasításban az <code>adatbazisnev</code> helyére azt a nevet írd, melyet adni szeretnél az adatbázisodnak. Például azt az adatbázist, melyet ebben a fejezetben terveztünk meg, a következő SQL utasítással hozhatod létre:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">DATABASE</span> VasarloiRendelesInformaciok
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ha egy adatbázis már létezik azon a néven melyet megadtál, akkor egy hibaüzenetet fogsz látni. Ezt a hibaüzenetet elkerülheted, ha egy <code>IF</code> kifejezést használsz az utasításodban a következőképpen:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">DATABASE</span> <span class="token keyword">IF</span> <span class="token operator">NOT</span> <span class="token keyword">EXISTS</span> VasarloiRendelesInformaciok
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ezzel az utasítással létrehozhatod az adatbázist, ha az még nem létezik, az utasítás azonban nem okoz hibát, ha az adatbázis már létezik. Ekkor egyszerűen csak nem hozza létre az új adatbázist. Miután létrehoztad az üres adatbázist elhelyezhetsz benne táblákat.</p><h3 id="adatbazis-torlese" tabindex="-1"><a class="header-anchor" href="#adatbazis-torlese" aria-hidden="true">#</a> Adatbázis törlése</h3><p>Bármely adatbázist törölheted, ha olyan fiókot használsz mely rendelkezik <code>DROP</code> jogosultságokkal. Amikor törölsz egy adatbázist, vele együtt törlődik az összes táblája és az azokban lévő összes adat is.</p><p>A következő SQL utasítással törölhetsz egy adatbázist:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DROP</span> <span class="token keyword">DATABASE</span> adatbazisnev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>A <code>DROP</code> utasítást nagyon óvatosan használd, mert nem lehet visszavonni. Miután eltávolítottál egy adatbázist, az örökre odalesz. Vele együtt eltűnik minden benne lévő adat is.</p><p>Ha az adatbázis nem létezik akkor egy hibaüzenet fog megjelenni. A következő utasítással kerülheted el, hogy hibaüzenet jelenjen meg:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DROP</span> <span class="token keyword">DATABASE</span> <span class="token keyword">IF</span> <span class="token operator">NOT</span> <span class="token keyword">EXISTS</span> adatbazisnev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ezzel az utasítással eltávolíthatod az adatbázist, ha az adott adatbázis létezik, ha pedig nem létezik az utasítás nem okoz hibát. Az utasítás csak csendben lefut.</p><h3 id="tablak-letrehozasa-es-az-elsodleges-kulcsok-meghatarozasa" tabindex="-1"><a class="header-anchor" href="#tablak-letrehozasa-es-az-elsodleges-kulcsok-meghatarozasa" aria-hidden="true">#</a> Táblák létrehozása és az elsődleges kulcsok meghatározása</h3><p>Bármely adatbázisba szúrhatsz be táblákat attól függetlenül, hogy új üres adatbázisról van-e szó melyet épp most hoztál létre vagy egy már meglévőről melyben már vannak táblák és adatok.<br> Amikor létrehozol egy táblát meg kell adnod a tábla definícióját is. Meg kell határoznod minden egyes oszlopát elnevezed őket, adattípust rendelsz hozzájuk és megadsz bármilyen egyéb szükséges definíciót.</p><div class="hint-container tip"><p class="hint-container-title">A következőkben néhány olyan definíciót láthatsz melyeket gyakran adunk meg oszlopokhoz:</p><p><code>NOT NULL</code>: Ebben az oszlopban kell lennie értéknek nem lehet üres.</p><p><code>DEFAULT ertek</code>: Ez az <code>ertek</code> kerül be az oszlopba, ha úgy hozol létre sort, hogy nem adsz meg más értéket az adott oszlophoz.</p><p><code>AUTO_INCREMENT</code>: Ez a definíció egy számsorozatot hoz létre. Ahogy beszúrod az egyes sorokat, az oszlop értéke mindig egy adott egész számmal nő a legutóbb megadott sor értékéhez képest. Az automatikus számokat felül is írhatod, ha egy megadott értéket rendelsz hozzá az adott oszlophoz.</p><p><code>UNSIGNED</code>: Ez a definíció azt jelzi, hogy az adott numerikus mező értékei soha nem lesznek negatívak.</p></div><p>Minden sorhoz meg kell határoznod az egyedi azonosítót - <em>az elsődleges kulcsot</em> - is. A táblának kell, hogy legyen egy olyan mezője vagy a mezőinek egy olyan kombinációja, melynek értéke minden sorban eltérő. Nem lehet két olyan sor melyben az elsődleges kulcs értéke ugyanaz. Ha megpróbálsz beszúrni egy olyan sort, melynek ugyanaz az elsődleges kulcsa mint egy olyan sornak mely már létezik a táblában akkor egy hibaüzenetet fogsz kapni és a sort nem fogod tudni beszúrni.</p><p>Időnként előfordulhat, hogy olyan táblákat szeretnél létrehozni melyek felépítése megegyezik egy meglévő tábláéval. Létrehozhatsz olyan táblát, mely egy üres másolat.</p><p>A <code>CREATE</code> utasítás segítségével szúrhatsz be táblákat adatbázisokba. Az utasítás a <code>CREATE TABLE</code> kulcsszavakkal kezdődik a következőképpen:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> tablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ezután kell megadnod az oszlopok neveit és definícióit. Minden oszlop információit vesszővel válaszd el a rákövetkező oszlop információitól. A teljes listát zárójelek között add meg. Minden oszlop neve után add meg annak adattípusát és minden szükséges definíciót.</p><p>A <code>CREATE TABLE</code> utasítás utolsó eleme azt adja meg, hogy melyik oszlop vagy mely oszlopok kombinációja az elsődleges kulcs. Az elsődleges kulcsot a következő formátumban adhatod meg:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">(</span>oszlopnev<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Az oszlopnév meghatározását zárójelek között add meg. Ha oszlopok együttesét használod elsődleges kulcsként, akkor minden oszlop nevét add meg vesszőkkel elválasztva egymástól. Meghatározhatod például az elsődleges kulcsot úgy, hogy <code>PRIMARY KEY(oszlopnev1, oszlopnev2)</code>.</p><p>A teljes <code>CREATE TABLE</code> utasítás alakja a következő:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> tablanev <span class="token punctuation">(</span>
 oszlopnev adattipus
 oszlopnev adattipus
<span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">(</span>oszlopnev<span class="token punctuation">)</span> <span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A következő kódrészletben a <code>VasarloiRendelesInformaciok</code> adatbázisban a <code>Vasarlo</code> táblájának létrehozásához használt SQL utasítást láthatod.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> Vasarlo<span class="token punctuation">(</span>
 vasarlo_azon <span class="token keyword">INT</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
 vezeteknev <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
 keresztnev <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
 utca <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
 varos <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
 megye <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
 iranyitoszam <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
 email <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">,</span> 
 telefon <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
 <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span><span class="token punctuation">(</span>vasarlo_azon<span class="token punctuation">)</span> <span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ha megpróbálsz létrehozni egy olyan táblát mely már létezik akkor egy hibaüzenetet fogsz látni. Elkerülheted, hogy ez a hibaüzenet megjelenjen, ha a következő <code>CREATE</code> utasítást használod:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> <span class="token keyword">IF</span> <span class="token operator">NOT</span> <span class="token keyword">EXISTS</span> tablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ha a tábla nem létezik akkor az utasítás létrehozza. Ha a tábla már létezik akkor az utasítás nem hozza létre, de hibaüzenetet sem ad vissza.</p><p>Létrehozhatsz olyan új táblát is mely egy meglévő tábla pontos mása, és ugyanolyan a felépítése a következőképpen:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> tablanev <span class="token operator">LIKE</span> regitablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Az új <code>tablanev</code> úgy jön létre, hogy ugyanolyan mezői és definíciói lesznek mint a <code>regitablanev</code> táblának. Az új táblában azonban akkor sem lesznek adatok, ha a régi táblában voltak, csak a struktúrát veszi át.</p><p>Miután létrehoztad a táblát lekérdezheted és így ellenőrizheted a felépítését, vagy törölheted.</p><div class="hint-container tip"><p class="hint-container-title">Ha meg szeretnéd nézni az adatbázisodban szereplő táblákat, használd a következő lekérdezést:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SHOW</span> <span class="token keyword">TABLES</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ha szeretnéd egy tábla felépítését látni, használd a következő lekérdezést:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">EXPLAIN</span> tablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></div><h3 id="tablak-eltavolitasa" tabindex="-1"><a class="header-anchor" href="#tablak-eltavolitasa" aria-hidden="true">#</a> Táblák eltávolítása</h3><p>Attól függetlenül törölhetsz táblákat, hogy üresek-e vagy vannak bennük adattok. Mielőtt valóban törölnél, egy táblát fontold meg, hogy tényleg törölni szeretnéd-e.<br> A táblák törlését nem lehet visszavonni. Ha eltávolítasz egy táblát akkor a tábla örökre odalesz. Emellett az összes adat is odavész, amelyek benne voltak.</p><p>Ha szeretnél törölni egy táblát, akkor használd a következő utasítást:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">DROP</span> <span class="token keyword">TABLE</span> tablanev
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="adatbazis-felepitesenek-modositasa" tabindex="-1"><a class="header-anchor" href="#adatbazis-felepitesenek-modositasa" aria-hidden="true">#</a> Adatbázis felépítésének módosítása</h3><p>Az adatbázis szerkezete nincs kőbe vésve. Bármely tábla nevét módosíthatod bármely táblába felvehetsz új oszlopokat és törölheted vagy átnevezheted a meglévő oszlopokat illetve bármely oszlop adattípusát vagy más tulajdonságát is módosíthatod.<br> Tegyük fel például hogy van egy adatbázisod melyben definiáltál egy <code>vezeteknev</code> nevű oszlopot <code>VARCHAR(20)</code> adattípussal. Akkor még elegendőnek tűnt a 20 karakter a vezetéknév tárolásához, de ez most már kevés és több karakterre lesz szükséged.</p><p>Az adatbázis struktúráját az <code>ALTER</code> utasítás segítségével módosíthatod. Ennek az utasításnak az alapvető formája az <code>ALTER TABLE tablanev</code> melyet a meghatározott módosítások követnek.</p><table><thead><tr><th>Módosítás</th><th>Leírás</th></tr></thead><tbody><tr><td><code>ADD oszlopnev</code></td><td>Új oszlopot szúr be.</td></tr><tr><td><code>ALTER oszlopnev SET DEFAULT ertek</code></td><td>Módosítja egy oszlop alapértelmezett értékét.</td></tr><tr><td><code>ALTER oszlopnev DROP DEFAULT</code></td><td>Eltávolítja egy oszlop alapértelmezett értékét.</td></tr><tr><td><code>CHANGE oszlopnev ujoszlopnev</code></td><td>Módosítja egy oszlop definícióját.</td></tr><tr><td><code>DROP oszlopnev</code></td><td>Töröl egy oszlopot az összes adattal együtt.</td></tr><tr><td><code>MODIFY oszlopnev</code></td><td>Módosítja egy oszlop definícióját.</td></tr><tr><td><code>RENAME ujtablanev</code></td><td>Átnevezi a táblát.</td></tr></tbody></table><p>A következő utasítással például <code>Ujvasarlo</code> névre nevezheted át a <code>Vasarlo</code> táblát:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> Vasarlo <span class="token keyword">RENAME</span> Ujvasarlo
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Egy másik példaként a következő utasítással a megadott oszlopot a megadott adattípusra és hosszra tudod módosítani:</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">TABLE</span> Vasarlo <span class="token keyword">MODIFY</span> vezeteknev <span class="token keyword">VARCHAR</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,145),o=[n];function d(i,r){return a(),t("div",null,o)}const c=e(l,[["render",d],["__file","lesson2.html.vue"]]);export{c as default};
